/**
 * AR runtime entry — dynamically loads the concrete runtime so the
 * initial viewer bundle doesn't bloat with WebXR / Three.js code on
 * devices that won't use it.
 */

import { detectCapabilities, pickRuntimePath } from './capabilities';
import type { ArRuntime, RuntimePath } from './types';

export interface PickRuntimeResult {
  readonly path: RuntimePath;
  readonly runtime: ArRuntime | null;
  /** Set when no runtime is available (preview-only). */
  readonly unavailableReason?: string;
}

/**
 * Pick + load the concrete runtime for the current device.
 *
 * Returns `runtime: null` for preview-only devices — callers should
 * render a "scan QR with phone" or "open on mobile" affordance.
 */
export async function pickRuntime(): Promise<PickRuntimeResult> {
  const caps = await detectCapabilities();
  const path = pickRuntimePath(caps);
  switch (path) {
    case 'webxr': {
      const { createWebXrRuntime } = await import('./webxr-runtime');
      return { path, runtime: createWebXrRuntime() };
    }
    case 'model-viewer': {
      const { createModelViewerRuntime } = await import('./model-viewer-runtime');
      return { path, runtime: createModelViewerRuntime() };
    }
    case 'preview-only':
      return {
        path,
        runtime: null,
        unavailableReason: 'This device does not support AR — open the link on a mobile device.',
      };
  }
}

export type {
  ArRuntime,
  RuntimePath,
  RuntimeEvent,
  RuntimeEventListener,
  ArCapabilities,
} from './types';
export { detectCapabilities, pickRuntimePath } from './capabilities';
export { RuntimeEventBus } from './event-bus';
