/**
 * Embedded viewer app entry point.
 *
 * Hosted at `ar.novagates.app/embed` (or any equivalent origin the
 * embed JS points the iframe at). Parses the query string, mounts the
 * UI, listens for host commands, emits events back to the parent.
 */

import { detectCapabilities, pickRuntime, pickRuntimePath } from './ar';
import type { ArRuntime } from './ar';
import { HostBridge } from './host-bridge';
import { parseQuery } from './query';
import { applyTheme } from './theme';
import { directionFor, langTagFor, pickStrings } from './i18n/strings';
import { findMockItem, listMockItems } from './mock-catalog';
import { render } from './ui/render';
import {
  ModelViewerAnimationAdapter,
  ModelViewerMaterialAdapter,
  type ModelViewerLike,
} from './ar/model-viewer-adapters';
import { AnimationController } from './ui/animation-controller';
import { MaterialSwapController } from './ui/material-swap';
import { mountSwatchOverlay, type SwatchOverlayHandle } from './ui/swatch-overlay';
import type { CommandEnvelope, EmbedLanguage, EmbedTheme } from './shared-types';
import type { RenderState } from './ui/render';
import type { Item } from '@nova-ar/types';

const APP_ELEMENT_ID = 'app';

/**
 * Per-model placement guidance shown in the AR bar. Derived from the
 * item's `placement` + `mountType` so every model tells the shopper which
 * real surface to aim the camera at — floor furniture at the floor, decor
 * at a tabletop, sconces at a wall, pendants at the ceiling.
 *
 * Surface DETECTION itself is driven by `ar-placement` (floor | wall) on
 * the <model-viewer>, which is set from the same fields — see
 * model-viewer-runtime.ts. Phone AR (Scene Viewer / Quick Look) supports
 * floor + wall planes only; there is no true ceiling anchor, so ceiling
 * fixtures are guided to a high wall and we say so honestly.
 */
function placementGuidance(item: Item): string {
  if (item.placement === 'floor') {
    return '📍 Point the camera at the FLOOR and move slowly until it’s detected, then tap to place.';
  }
  if (item.placement === 'surface') {
    return '📍 Point at a TABLE or flat surface, wait for the dots, then tap to place.';
  }
  if (item.placement === 'wall-ceiling' && item.mountType === 'ceiling') {
    return '📍 Ceiling fixture — aim HIGH on a wall near the ceiling. (Phone AR can’t anchor to ceilings yet, so it mounts on the wall.)';
  }
  // wall-mounted (sconces, art, mirrors)
  return '📍 Point the camera at a WALL and move slowly until it’s detected, then tap to place.';
}

async function boot(): Promise<void> {
  const config = parseQuery(window.location.search);
  applyTheme(config.theme);
  applyLanguage(config.language);

  const root = document.getElementById(APP_ELEMENT_ID);
  if (!root) {
    console.error(`[nova-ar-viewer] no #${APP_ELEMENT_ID} element`);
    return;
  }

  const bridge = new HostBridge();
  const items = listMockItems();
  // Detect AR capability synchronously (best-effort) so the first
  // render reflects the runtime path. The real runtime is fetched
  // lazily on launch.
  const caps = await detectCapabilities();
  const path = pickRuntimePath(caps);

  const state: RenderState = {
    language: config.language,
    currency: config.currency,
    items,
    selectedItemId: config.itemId,
    placementHint: null,
    arRuntimeAvailable: path !== 'preview-only',
    errorMessage: null,
  };

  let activeRuntime: ArRuntime | null = null;
  let arOverlay: HTMLElement | null = null;
  // Active per-item controllers — set on AR launch, torn down on session.end.
  let materialController: MaterialSwapController | null = null;
  let animationController: AnimationController | null = null;
  let swatchOverlay: SwatchOverlayHandle | null = null;

  const setState = (patch: Partial<RenderState>): void => {
    Object.assign(state, patch);
    render(root, state, callbacks);
    if (patch.selectedItemId) {
      bridge.emit({ kind: 'item.viewed', itemId: patch.selectedItemId });
    }
  };

  const launchAr = async (itemId: string): Promise<void> => {
    let arStatusEl: HTMLElement | null = null;
    const item = findMockItem(itemId);
    if (!item) {
      bridge.emit({ kind: 'error', code: 'item.not-found', message: `unknown item ${itemId}` });
      return;
    }
    if (activeRuntime) {
      // Already in a session — end it before starting another.
      await activeRuntime.end().catch(() => undefined);
      activeRuntime = null;
    }
    const picked = await pickRuntime();
    if (!picked.runtime) {
      bridge.emit({
        kind: 'error',
        code: 'ar.unavailable',
        message: picked.unavailableReason ?? 'AR not supported on this device',
      });
      setState({ errorMessage: picked.unavailableReason ?? null });
      return;
    }
    activeRuntime = picked.runtime;
    // Forward every runtime event up to the host bridge.
    activeRuntime.on((event) => {
      bridge.emit(event);
      if (event.kind === 'error' && arStatusEl) {
        arStatusEl.textContent = `⚠ ${event.message || event.code}`;
        arStatusEl.style.display = 'block';
      }
      if (event.kind === 'session.end') {
        swatchOverlay?.dispose();
        swatchOverlay = null;
        materialController = null;
        animationController = null;
        arOverlay?.remove();
        arOverlay = null;
        activeRuntime = null;
      }
    });
    // Build a full-screen overlay: a top bar (close + status/hint) plus a
    // model host the runtime renders into. The runtime is mounted into a
    // CHILD host (not arOverlay itself) because it calls
    // container.replaceChildren(), which would otherwise wipe our chrome.
    arOverlay = document.createElement('div');
    arOverlay.id = 'ar-overlay';
    arOverlay.style.cssText =
      'position:fixed;inset:0;z-index:9999;background:#0b0b0f;display:flex;flex-direction:column;';
    const arBar = document.createElement('div');
    arBar.style.cssText =
      'display:flex;align-items:center;gap:10px;padding:10px 14px;background:rgba(0,0,0,0.5);';
    const arClose = document.createElement('button');
    arClose.textContent = '✕';
    arClose.setAttribute('aria-label', 'Close');
    arClose.style.cssText =
      'width:40px;height:40px;flex:0 0 auto;border:0;border-radius:8px;background:rgba(255,255,255,0.12);color:#fff;font-size:18px;cursor:pointer;';
    arClose.addEventListener('click', () => {
      void activeRuntime?.end();
    });
    // Our own prominent AR trigger. model-viewer's default corner "cube"
    // gets hidden behind the bottom swatch row, so this always-visible
    // button — which calls model-viewer's activateAR() — is the reliable
    // way into AR. It looks the model-viewer up at click time.
    const arGo = document.createElement('button');
    arGo.textContent = '📷 View in your room';
    arGo.style.cssText =
      'flex:0 0 auto;border:0;border-radius:10px;padding:0 16px;height:40px;background:#16a34a;color:#fff;font:600 14px/1 system-ui,sans-serif;cursor:pointer;';
    const arHint = document.createElement('div');
    arHint.textContent = 'Loading 3D…';
    arHint.style.cssText = 'flex:1;color:#cbd5e1;font-size:12px;min-width:0;';
    arStatusEl = document.createElement('div');
    arStatusEl.style.cssText =
      'flex:2;color:#fecaca;font-size:12px;display:none;white-space:pre-wrap;';
    arBar.append(arClose, arGo, arHint, arStatusEl);
    const arModelHost = document.createElement('div');
    arModelHost.style.cssText = 'flex:1;position:relative;min-height:0;';
    arGo.addEventListener('click', () => {
      const mv = arModelHost.querySelector('model-viewer') as
        | (HTMLElement & { activateAR?: () => Promise<void> })
        | null;
      if (!mv || typeof mv.activateAR !== 'function') {
        if (arStatusEl) {
          arStatusEl.textContent = '⚠ AR not ready yet — wait for the model to finish loading.';
          arStatusEl.style.display = 'block';
        }
        return;
      }
      void Promise.resolve(mv.activateAR()).catch((err: unknown) => {
        if (arStatusEl) {
          arStatusEl.textContent = `⚠ ${err instanceof Error ? err.message : 'AR could not start'}`;
          arStatusEl.style.display = 'block';
        }
      });
    });
    arOverlay.append(arBar, arModelHost);
    document.body.append(arOverlay);
    try {
      await activeRuntime.launch(item, arModelHost);
      // After the runtime has rendered, wire the interaction controllers.
      // model-viewer path: introspect the <model-viewer> element the
      // runtime mounted into arOverlay and bind the concrete adapters.
      // WebXR path: the Three.js scene-graph adapter binding lands once
      // the WebXR runtime exposes its `gltf` / `mixer` (a follow-up).
      const modelViewerEl = arOverlay.querySelector('model-viewer') as
        | (HTMLElement & ModelViewerLike)
        | null;
      if (modelViewerEl) {
        // Surface load progress in the top bar so a slow/failed model
        // load is visible instead of a silent black panel.
        const readyHint = `Tap “View in your room”. ${placementGuidance(item)}`;
        modelViewerEl.addEventListener('progress', (ev: Event) => {
          const pct = Math.round(
            (((ev as CustomEvent<{ totalProgress?: number }>).detail?.totalProgress ??
              0) as number) * 100,
          );
          arHint.textContent = pct < 100 ? `Loading 3D… ${pct}%` : readyHint;
        });
        modelViewerEl.addEventListener('load', () => {
          arHint.textContent = readyHint;
        });
        if ((item.swappableMaterials?.length ?? 0) > 0) {
          materialController = new MaterialSwapController({
            item,
            adapter: new ModelViewerMaterialAdapter(modelViewerEl),
          });
        }
        if ((item.playableAnimations?.length ?? 0) > 0) {
          animationController = new AnimationController({
            item,
            adapter: new ModelViewerAnimationAdapter(modelViewerEl, (name) => {
              animationController?.onClipFinished(name);
              swatchOverlay?.setActiveAnimations(animationController?.activeNames() ?? []);
            }),
          });
        }
      }
      // Mount the shopper-facing chip overlay if either capability is
      // active for the item. Capability gates land via the embed config.
      if (materialController || animationController) {
        swatchOverlay = mountSwatchOverlay({
          hostEl: arOverlay,
          callbacks: {
            onMaterialColor: (materialName, hex) => {
              const r = materialController?.swap(materialName, hex);
              if (r?.ok) swatchOverlay?.setSelectedSwatch(r.materialName, r.hex);
            },
            onAnimation: (name) => {
              const r = animationController?.play(name);
              if (r?.ok) swatchOverlay?.setActiveAnimations(animationController!.activeNames());
            },
          },
          capabilities: {
            showMaterialSwap: Boolean(materialController),
            showAnimations: Boolean(animationController),
          },
        });
        swatchOverlay.setActiveItem(item);
      }
    } catch (err) {
      bridge.emit({
        kind: 'error',
        code: 'ar.launch-failed',
        message: (err as Error).message,
      });
      swatchOverlay?.dispose();
      swatchOverlay = null;
      materialController = null;
      animationController = null;
      arOverlay?.remove();
      arOverlay = null;
      activeRuntime = null;
    }
  };

  const callbacks = {
    onSelectItem(itemId: string): void {
      setState({ selectedItemId: itemId });
    },
    onLaunchAr(itemId: string): void {
      void launchAr(itemId);
    },
    onRetry(): void {
      setState({ errorMessage: null });
    },
  };

  bridge.start((cmd) =>
    handleCommand(cmd, setState, {
      materialController: () => materialController,
      animationController: () => animationController,
      swatchOverlay: () => swatchOverlay,
      emitError: (code, message) => bridge.emit({ kind: 'error', code, message }),
    }),
  );

  // Initial render + handshake — tell the host which runtime path we
  // picked so it can show the right "open on phone" / "ready to scan"
  // affordance on its side.
  render(root, state, callbacks);
  bridge.emit({ kind: 'session.start', runtimePath: path });
}

interface CommandContext {
  materialController(): MaterialSwapController | null;
  animationController(): AnimationController | null;
  swatchOverlay(): SwatchOverlayHandle | null;
  emitError(code: string, message: string): void;
}

function handleCommand(
  cmd: CommandEnvelope,
  setState: (p: Partial<RenderState>) => void,
  ctx: CommandContext,
): void {
  switch (cmd.kind) {
    case 'selectItem': {
      const itemId = (cmd.payload as { itemId?: string })?.itemId;
      if (typeof itemId === 'string' && itemId.length > 0) {
        setState({ selectedItemId: itemId });
      }
      return;
    }
    case 'setLanguage': {
      const language = (cmd.payload as { language?: EmbedLanguage })?.language;
      if (language) {
        applyLanguage(language);
        setState({ language });
      }
      return;
    }
    case 'setTheme': {
      const theme = (cmd.payload as { theme?: EmbedTheme })?.theme;
      if (theme) {
        applyTheme(theme);
      }
      return;
    }
    case 'setSkin': {
      // Skin handling lands in S4; ack silently for now.
      return;
    }
    case 'setMaterialColor': {
      const payload = cmd.payload as { materialName?: string; hex?: string } | undefined;
      const ctl = ctx.materialController();
      if (!ctl) {
        ctx.emitError(
          'material.no-active-session',
          'setMaterialColor requires an active AR session',
        );
        return;
      }
      if (!payload?.materialName || !payload.hex) {
        ctx.emitError('material.invalid', 'setMaterialColor requires materialName + hex');
        return;
      }
      const r = ctl.swap(payload.materialName, payload.hex);
      if (!r.ok) {
        ctx.emitError(`material.${r.reason}`, `material swap rejected: ${r.reason}`);
      } else {
        ctx.swatchOverlay()?.setSelectedSwatch(r.materialName, r.hex);
      }
      return;
    }
    case 'playAnimation': {
      const payload = cmd.payload as { name?: string } | undefined;
      const ctl = ctx.animationController();
      if (!ctl) {
        ctx.emitError('animation.no-active-session', 'playAnimation requires an active AR session');
        return;
      }
      if (!payload?.name) {
        ctx.emitError('animation.invalid', 'playAnimation requires a name');
        return;
      }
      const r = ctl.play(payload.name);
      if (!r.ok) {
        ctx.emitError(`animation.${r.reason}`, `play rejected: ${r.reason}`);
      } else {
        ctx.swatchOverlay()?.setActiveAnimations(ctl.activeNames());
      }
      return;
    }
    case 'stopAnimation': {
      const payload = cmd.payload as { name?: string } | undefined;
      const ctl = ctx.animationController();
      if (!ctl) return;
      ctl.stop(payload?.name);
      ctx.swatchOverlay()?.setActiveAnimations(ctl.activeNames());
      return;
    }
    case 'updateProduct': {
      // Product context flows through state; viewer UI doesn't render
      // a separate "buy" CTA in S3 — that's S11 with the e-commerce
      // adapters. Ignore silently for now.
      return;
    }
  }
}

function applyLanguage(language: EmbedLanguage): void {
  document.documentElement.setAttribute('lang', langTagFor(language));
  document.documentElement.setAttribute('dir', directionFor(language));
  document.title = pickStrings(language)['app.title'];
}

if (typeof document !== 'undefined') {
  if (document.readyState === 'loading') {
    document.addEventListener('DOMContentLoaded', () => {
      void boot();
    });
  } else {
    void boot();
  }
}

// Exported for tests.
export { boot };
