/**
 * Capability detection — which AR runtime path is available right now?
 *
 * Order of preference:
 *   1. model-viewer native handoff — Android Scene Viewer (ARCore) /
 *      iOS Quick Look. Rock-solid on phones.
 *   2. WebXR immersive-ar — only where there's NO native handoff (MR
 *      headsets, desktop XR). In-browser WebXR on mobile Chrome is
 *      frequently a black / no-passthrough session, so phones must NOT
 *      prefer it over Scene Viewer / Quick Look.
 *   3. preview-only (no AR — desktop browser without WebXR)
 */

import type { ArCapabilities, RuntimePath } from './types';

interface XrLike {
  isSessionSupported(mode: string): Promise<boolean>;
}

function detectPlatform(ua: string): ArCapabilities['platform'] {
  const lower = ua.toLowerCase();
  if (/iphone|ipad|ipod/.test(lower)) return 'ios';
  if (/android/.test(lower)) return 'android';
  if (/mac|win|linux|cros/.test(lower)) return 'desktop';
  return 'unknown';
}

async function probeWebXr(nav: Navigator): Promise<boolean> {
  const xr = (nav as Navigator & { xr?: XrLike }).xr;
  if (!xr || typeof xr.isSessionSupported !== 'function') return false;
  try {
    return await xr.isSessionSupported('immersive-ar');
  } catch {
    return false;
  }
}

export async function detectCapabilities(nav: Navigator = navigator): Promise<ArCapabilities> {
  const platform = detectPlatform(nav.userAgent ?? '');
  const webxr = await probeWebXr(nav);
  return {
    webxrImmersiveAr: webxr,
    quickLookAvailable: platform === 'ios',
    sceneViewerAvailable: platform === 'android',
    platform,
  };
}

export function pickRuntimePath(caps: ArCapabilities): RuntimePath {
  // Prefer the OS-native AR handoff (Android Scene Viewer / iOS Quick
  // Look) over in-browser WebXR — WebXR immersive-ar on mobile Chrome is
  // frequently black/unreliable, while Scene Viewer / Quick Look are
  // production-grade. WebXR is only the right pick when there's no native
  // handoff (e.g. an MR headset or desktop XR rig).
  if (caps.quickLookAvailable || caps.sceneViewerAvailable) return 'model-viewer';
  if (caps.webxrImmersiveAr) return 'webxr';
  return 'preview-only';
}
