/**
 * Parse the iframe's query-string config sent from the host embed.
 *
 * The embed JS builds the URL via `?tenant=…&item=…&theme=…&lang=…`.
 * We mirror that here so a hand-typed URL also works for local dev.
 */

import type { EmbedLanguage, EmbedTheme } from './shared-types';
import { isLanguage, isTheme } from './shared-types';

export interface ViewerConfig {
  readonly tenant: string;
  readonly itemId: string | null;
  readonly theme: EmbedTheme;
  readonly language: EmbedLanguage;
  readonly skin: string | null;
  readonly productId: string | null;
  readonly currency: string | null;
  readonly priceCents: number | null;
}

const DEFAULT_TENANT = 'demo';
const DEFAULT_THEME: EmbedTheme = 'auto';
const DEFAULT_LANGUAGE: EmbedLanguage = 'en';

export function parseQuery(search: string): ViewerConfig {
  const params = new URLSearchParams(search);
  const themeRaw = params.get('theme') ?? DEFAULT_THEME;
  const langRaw = params.get('lang') ?? DEFAULT_LANGUAGE;
  const priceRaw = params.get('priceCents');
  return {
    tenant: params.get('tenant') ?? DEFAULT_TENANT,
    itemId: params.get('item'),
    theme: isTheme(themeRaw) ? themeRaw : DEFAULT_THEME,
    language: isLanguage(langRaw) ? langRaw : DEFAULT_LANGUAGE,
    skin: params.get('skin'),
    productId: params.get('productId'),
    currency: params.get('currency'),
    priceCents: priceRaw ? Number.parseInt(priceRaw, 10) : null,
  };
}
