/**
 * @nova-ar/errors — standard error classes + codes.
 *
 * Every SDK and service throws one of these subclasses so callers can
 * pattern-match on `err.code` rather than parsing free-form messages.
 */

/** Base class for every Novagates AR Studio error. */
export class NovaArError extends Error {
  constructor(
    public readonly code: string,
    message: string,
    cause?: unknown,
  ) {
    super(message, cause !== undefined ? { cause } : undefined);
    this.name = 'NovaArError';
  }
}

/** SDK-side error (client). */
export class ArSdkError extends NovaArError {
  override name = 'ArSdkError';
}

/** Network / HTTP transport error. */
export class HttpError extends NovaArError {
  constructor(
    public readonly status: number,
    code: string,
    message: string,
    cause?: unknown,
  ) {
    super(code, message, cause);
    this.name = 'HttpError';
  }
}

/** Catalog server / business-rule error. */
export class CatalogError extends NovaArError {
  override name = 'CatalogError';
}

/** Conversion pipeline error (mesh / texture / format). */
export class PipelineError extends NovaArError {
  override name = 'PipelineError';
}

/** Validation error (input failed schema or rule). */
export class ValidationError extends NovaArError {
  constructor(
    code: string,
    message: string,
    public readonly fieldPath?: string,
    cause?: unknown,
  ) {
    super(code, message, cause);
    this.name = 'ValidationError';
  }
}

/** Reserved error codes — kept as a typed enum-like for grep-ability. */
export const ERROR_CODES = {
  // Auth
  AUTH_MISSING_API_KEY: 'auth.missing-api-key',
  AUTH_INVALID_TOKEN: 'auth.invalid-token',
  AUTH_EXPIRED: 'auth.expired',
  // Catalog
  CATALOG_ITEM_NOT_FOUND: 'catalog.item.not-found',
  CATALOG_TENANT_QUOTA: 'catalog.tenant.quota-exceeded',
  CATALOG_INVALID_FILTER: 'catalog.filter.invalid',
  // Pipeline
  PIPELINE_FORMAT_UNSUPPORTED: 'pipeline.format.unsupported',
  PIPELINE_BBOX_TOO_LARGE: 'pipeline.bbox.too-large',
  PIPELINE_BBOX_TOO_SMALL: 'pipeline.bbox.too-small',
  PIPELINE_USDZ_CONVERSION: 'pipeline.usdz.conversion-failed',
  PIPELINE_TEXTURE_FORMAT: 'pipeline.textures.format-unsupported',
  // SDK
  SDK_NO_AR_RUNTIME: 'sdk.runtime.unavailable',
  SDK_NO_SELECTION: 'sdk.selection.required',
  SDK_INVALID_ITEM: 'sdk.item.invalid',
  SDK_TOO_MANY_ITEMS: 'sdk.scene.too-many-items',
  SDK_SCALE_OUT_OF_RANGE: 'sdk.scale.out-of-range',
  SDK_UNKNOWN_PLACEMENT: 'sdk.placement.unknown',
  // HTTP
  HTTP_BAD_GATEWAY: 'http.bad-gateway',
  HTTP_TIMEOUT: 'http.timeout',
} as const;

export type ErrorCode = (typeof ERROR_CODES)[keyof typeof ERROR_CODES];
