/** Pick a language map (with ar-KW fallback). */
export function pickStrings(language: EmbedLanguage): Record<StringKey, string> {
  switch (language) {
    case 'en':
      return en;
    case 'fr':
      return fr;
    case 'ar':
      return ar;
    case 'ar-KW':
      return { ...ar, ...arKw } as Record<StringKey, string>;
  }
}

/** Direction the document should render in for a given language. */
export function directionFor(language: EmbedLanguage): 'ltr' | 'rtl' {
  return language === 'ar' || language === 'ar-KW' ? 'rtl' : 'ltr';
}

/** HTML lang attribute value. */
export function langTagFor(language: EmbedLanguage): string {
  switch (language) {
    case 'ar-KW':
      return 'ar-KW';
    case 'ar':
      return 'ar';
    case 'fr':
      return 'fr';
    case 'en':
      return 'en';
  }
}
