/**
 * The viewer-side counterpart to embed's `PostMessageBridge`.
 *
 * Inside the iframe, we:
 *   - listen for command messages from the host (event.source === window.parent)
 *   - emit events upward via window.parent.postMessage with the parent's origin
 *
 * Security: same triple-check pattern as the embed side — parent
 * origin allow-list, source-window match, envelope shape guard.
 */

import { ArSdkError } from '@nova-ar/errors';
import type { BridgeMessage, CommandEnvelope, NovaArEvent } from './shared-types';
import { isCommandKind } from './shared-types';

export type CommandHandler = (command: CommandEnvelope) => void;

export interface HostBridgeOptions {
  /**
   * Origin we trust to send us commands. Default: '*' until the embed
   * publishes one via a handshake. In production this MUST be set to
   * the host's origin (passed via query param or postMessage 'init').
   */
  readonly allowedParentOrigin?: string;
  /** Override `window` (used in tests). */
  readonly host?: Window;
}

const NOVA_ENVELOPE_VERSION = 1;
const ALLOWED_TYPES = new Set(['event', 'command', 'ack']);

export class HostBridge {
  private readonly host: Window;
  private allowedParentOrigin: string;
  private commandHandler: CommandHandler | null = null;
  private nextSeq = 1;
  private listener: ((e: MessageEvent) => void) | null = null;

  constructor(opts: HostBridgeOptions = {}) {
    this.host = opts.host ?? window;
    this.allowedParentOrigin = opts.allowedParentOrigin ?? '*';
  }

  /** Update the parent origin once the handshake has revealed it. */
  setAllowedParentOrigin(origin: string): void {
    this.allowedParentOrigin = origin;
  }

  /** Start listening for commands from the host. */
  start(handler: CommandHandler): void {
    if (this.listener) {
      throw new ArSdkError('host-bridge.already-started', 'HostBridge already started');
    }
    this.commandHandler = handler;
    this.listener = (event: MessageEvent) => this.onMessage(event);
    this.host.addEventListener('message', this.listener);
  }

  /** Emit an event UP to the host page. */
  emit(event: NovaArEvent): void {
    if (!this.host.parent || this.host.parent === this.host) {
      // No parent (e.g. opened standalone for testing) — emit to console
      // so a developer can see what would have gone over the wire.
      console.warn('[nova-ar-viewer] no host parent; event dropped:', event);
      return;
    }
    const envelope: BridgeMessage = {
      _nova: true,
      v: NOVA_ENVELOPE_VERSION,
      id: this.makeId(),
      type: 'event',
      payload: event,
    };
    this.host.parent.postMessage(envelope, this.allowedParentOrigin);
  }

  /** Tear down the listener. */
  stop(): void {
    if (this.listener) {
      this.host.removeEventListener('message', this.listener);
      this.listener = null;
    }
    this.commandHandler = null;
  }

  private makeId(): string {
    return `v_${Date.now()}_${this.nextSeq++}`;
  }

  private onMessage(event: MessageEvent): void {
    if (!this.commandHandler) return;
    // Source must be the parent window.
    if (event.source !== this.host.parent) return;
    // Origin check — if configured, must match exactly.
    if (this.allowedParentOrigin !== '*' && event.origin !== this.allowedParentOrigin) return;
    // Envelope guard.
    if (!isBridgeMessage(event.data)) return;
    if (event.data.type !== 'command') return;
    const inner = event.data.payload as { kind?: unknown; payload?: unknown };
    if (!isCommandKind(inner.kind)) return;
    this.commandHandler({ kind: inner.kind, payload: inner.payload });
  }
}

function isBridgeMessage(value: unknown): value is BridgeMessage {
  if (typeof value !== 'object' || value === null) return false;
  const v = value as Record<string, unknown>;
  if (v._nova !== true) return false;
  if (v.v !== NOVA_ENVELOPE_VERSION) return false;
  if (typeof v.id !== 'string') return false;
  if (typeof v.type !== 'string' || !ALLOWED_TYPES.has(v.type)) return false;
  return true;
}
