/**
 * Shopper-facing chip overlay for material colour + animation + scale.
 *
 * Pure DOM (no framework) so it works on every embed runtime + adds
 * zero React weight. Layered above the active runtime element (the
 * `<model-viewer>` or the WebXR canvas), positioned at the bottom of
 * the iframe with a horizontally-scrollable row per surface:
 *
 *   ▼ Material rows (one per `swappableMaterials[i]`)
 *     [ Fabric: ● ● ● ● ]   ← circular swatches; selected has a ring
 *
 *   ▼ Animation row (when `playableAnimations` is non-empty)
 *     [ ▶ Open ]  [ ↻ Pulse ]   ← chip per clip
 *
 *   ▼ Scale slider (when ar-scale policy is 'free')
 *     [ — ━━●━━ + ]
 *
 * Each row is independently capability-gated by the host:
 * `showMaterialSwap`, `showAnimations`, `showScale`. A brand on the
 * basic plan ships none of them; the deluxe plan ships all three.
 * The overlay is mountable per-item via `setActiveItem(item)`; passing
 * `null` tears down every chip.
 */

import type { Item, PlayableAnimation, SwappableMaterial } from '@nova-ar/types';

export interface SwatchOverlayCallbacks {
  /** Called when the shopper clicks a colour swatch. */
  onMaterialColor(materialName: string, hex: string): void;
  /** Called when the shopper taps an animation chip. */
  onAnimation(name: string): void;
  /** Called when the shopper drags the scale slider. */
  onScaleChange?(scale01: number): void;
  /** Called when the shopper hits the reset arrow on the materials row. */
  onResetMaterials?(): void;
}

export interface SwatchOverlayOptions {
  readonly hostEl: HTMLElement;
  readonly callbacks: SwatchOverlayCallbacks;
  /** Which sections to render. Defaults to all true; brand caps can flip. */
  readonly capabilities?: {
    readonly showMaterialSwap?: boolean;
    readonly showAnimations?: boolean;
    readonly showScale?: boolean;
  };
  /** Labels (i18n hook). */
  readonly labels?: Partial<SwatchOverlayLabels>;
  /** RTL flag — flips chip order + uses inline-start instead of left. */
  readonly dir?: 'ltr' | 'rtl';
}

export interface SwatchOverlayLabels {
  readonly resetMaterials: string;
  readonly scaleLabel: string;
  readonly animationsHeading: string;
  readonly materialsHeading: string;
}

const DEFAULT_LABELS: SwatchOverlayLabels = {
  resetMaterials: 'Reset',
  scaleLabel: 'Size',
  animationsHeading: 'Animations',
  materialsHeading: 'Colours',
};

export interface SwatchOverlayHandle {
  setActiveItem(item: Item | null): void;
  setSelectedSwatch(materialName: string, hex: string): void;
  setActiveAnimations(names: readonly string[]): void;
  dispose(): void;
}

export function mountSwatchOverlay(opts: SwatchOverlayOptions): SwatchOverlayHandle {
  const labels = { ...DEFAULT_LABELS, ...opts.labels };
  const caps = {
    showMaterialSwap: true,
    showAnimations: true,
    showScale: false, // off by default — most furniture is fixed-scale
    ...opts.capabilities,
  };
  const root = document.createElement('div');
  root.className = 'nova-ar-swatch-overlay';
  root.setAttribute('dir', opts.dir ?? 'ltr');
  root.style.cssText = `
    position: absolute;
    inset-inline-start: 0;
    inset-inline-end: 0;
    bottom: 0;
    padding: 12px 16px env(safe-area-inset-bottom, 12px) 16px;
    background: linear-gradient(to top, rgba(15, 23, 42, 0.78), rgba(15, 23, 42, 0));
    pointer-events: none;
    z-index: 10;
    display: flex;
    flex-direction: column;
    gap: 12px;
  `;
  opts.hostEl.appendChild(root);

  let activeItem: Item | null = null;
  const swatchElements = new Map<string, HTMLButtonElement[]>();
  const animationElements = new Map<string, HTMLButtonElement>();
  let materialsSection: HTMLDivElement | null = null;
  let animationsSection: HTMLDivElement | null = null;
  let scaleSection: HTMLDivElement | null = null;

  function render(): void {
    materialsSection?.remove();
    animationsSection?.remove();
    scaleSection?.remove();
    swatchElements.clear();
    animationElements.clear();
    materialsSection = null;
    animationsSection = null;
    scaleSection = null;
    if (!activeItem) return;

    if (caps.showMaterialSwap && (activeItem.swappableMaterials?.length ?? 0) > 0) {
      materialsSection = renderMaterialsSection(
        activeItem.swappableMaterials!,
        opts.callbacks,
        labels,
        swatchElements,
      );
      root.appendChild(materialsSection);
    }
    if (caps.showAnimations && (activeItem.playableAnimations?.length ?? 0) > 0) {
      animationsSection = renderAnimationsSection(
        activeItem.playableAnimations!,
        opts.callbacks,
        labels,
        animationElements,
      );
      root.appendChild(animationsSection);
    }
    if (caps.showScale && opts.callbacks.onScaleChange) {
      scaleSection = renderScaleSection(opts.callbacks.onScaleChange, labels);
      root.appendChild(scaleSection);
    }
  }

  render();

  return {
    setActiveItem(item: Item | null): void {
      activeItem = item;
      render();
    },
    setSelectedSwatch(materialName: string, hex: string): void {
      const row = swatchElements.get(materialName);
      if (!row) return;
      const normalised = normaliseHex(hex);
      for (const btn of row) {
        const swatchHex = btn.dataset['hex'];
        const isSelected = swatchHex === normalised;
        btn.setAttribute('aria-pressed', String(isSelected));
        btn.style.boxShadow = isSelected
          ? '0 0 0 3px #ffffff, 0 0 0 5px rgba(15, 23, 42, 0.6)'
          : 'inset 0 0 0 1px rgba(255, 255, 255, 0.5)';
      }
    },
    setActiveAnimations(names: readonly string[]): void {
      const set = new Set(names);
      for (const [name, btn] of animationElements) {
        const isActive = set.has(name);
        btn.setAttribute('aria-pressed', String(isActive));
        btn.style.background = isActive
          ? 'linear-gradient(135deg, #0284c7, #0369a1)'
          : 'rgba(15, 23, 42, 0.72)';
      }
    },
    dispose(): void {
      root.remove();
      swatchElements.clear();
      animationElements.clear();
    },
  };
}

function renderMaterialsSection(
  rows: readonly SwappableMaterial[],
  cb: SwatchOverlayCallbacks,
  labels: SwatchOverlayLabels,
  swatchElements: Map<string, HTMLButtonElement[]>,
): HTMLDivElement {
  const section = document.createElement('div');
  section.className = 'nova-ar-section nova-ar-section--materials';
  section.style.cssText = 'display: flex; flex-direction: column; gap: 8px; pointer-events: auto;';

  const heading = document.createElement('div');
  heading.className = 'nova-ar-section__heading';
  heading.textContent = labels.materialsHeading;
  heading.style.cssText =
    'font: 600 11px/1 system-ui, sans-serif; color: rgba(255,255,255,0.8); letter-spacing: 0.06em; text-transform: uppercase;';
  section.appendChild(heading);

  for (const row of rows) {
    const rowEl = document.createElement('div');
    rowEl.className = 'nova-ar-swatch-row';
    rowEl.style.cssText = 'display: flex; align-items: center; gap: 10px; flex-wrap: wrap;';
    const rowLabel = document.createElement('span');
    rowLabel.textContent = row.label;
    rowLabel.style.cssText =
      'font: 600 13px/1 system-ui, sans-serif; color: #f8fafc; min-width: 60px;';
    rowEl.appendChild(rowLabel);
    const buttons: HTMLButtonElement[] = [];
    for (const hex of row.palette) {
      const btn = document.createElement('button');
      const normalised = normaliseHex(hex);
      btn.type = 'button';
      btn.className = 'nova-ar-swatch';
      btn.dataset['hex'] = normalised;
      btn.dataset['material'] = row.materialName;
      btn.setAttribute('aria-label', `${row.label} ${normalised}`);
      btn.setAttribute('aria-pressed', 'false');
      btn.style.cssText = `
        width: 32px;
        height: 32px;
        border-radius: 50%;
        border: 0;
        background: ${normalised};
        cursor: pointer;
        box-shadow: inset 0 0 0 1px rgba(255, 255, 255, 0.5);
        transition: transform 120ms ease, box-shadow 120ms ease;
      `;
      btn.addEventListener('click', () => cb.onMaterialColor(row.materialName, normalised));
      rowEl.appendChild(btn);
      buttons.push(btn);
    }
    swatchElements.set(row.materialName, buttons);
    section.appendChild(rowEl);
  }

  if (cb.onResetMaterials) {
    const resetBtn = document.createElement('button');
    resetBtn.type = 'button';
    resetBtn.textContent = `↻ ${labels.resetMaterials}`;
    resetBtn.style.cssText = `
      align-self: flex-start;
      padding: 6px 10px;
      border-radius: 12px;
      background: rgba(255, 255, 255, 0.12);
      color: #f8fafc;
      border: 0;
      font: 600 12px/1 system-ui, sans-serif;
      cursor: pointer;
      pointer-events: auto;
    `;
    resetBtn.addEventListener('click', () => cb.onResetMaterials?.());
    section.appendChild(resetBtn);
  }
  return section;
}

function renderAnimationsSection(
  clips: readonly PlayableAnimation[],
  cb: SwatchOverlayCallbacks,
  labels: SwatchOverlayLabels,
  animationElements: Map<string, HTMLButtonElement>,
): HTMLDivElement {
  const section = document.createElement('div');
  section.className = 'nova-ar-section nova-ar-section--animations';
  section.style.cssText = 'display: flex; flex-direction: column; gap: 8px; pointer-events: auto;';
  const heading = document.createElement('div');
  heading.textContent = labels.animationsHeading;
  heading.style.cssText =
    'font: 600 11px/1 system-ui, sans-serif; color: rgba(255,255,255,0.8); letter-spacing: 0.06em; text-transform: uppercase;';
  section.appendChild(heading);
  const row = document.createElement('div');
  row.style.cssText = 'display: flex; gap: 8px; flex-wrap: wrap;';
  for (const clip of clips) {
    const btn = document.createElement('button');
    btn.type = 'button';
    btn.className = 'nova-ar-anim-chip';
    btn.setAttribute('aria-label', `${labels.animationsHeading}: ${clip.label}`);
    btn.setAttribute('aria-pressed', 'false');
    btn.textContent = `${clip.glyph ?? '▶'} ${clip.label}`;
    btn.style.cssText = `
      padding: 8px 14px;
      min-height: 36px;
      border-radius: 18px;
      background: rgba(15, 23, 42, 0.72);
      color: #f8fafc;
      border: 1px solid rgba(255, 255, 255, 0.2);
      font: 600 13px/1 system-ui, sans-serif;
      cursor: pointer;
      pointer-events: auto;
      display: inline-flex;
      align-items: center;
      gap: 6px;
    `;
    btn.addEventListener('click', () => cb.onAnimation(clip.name));
    row.appendChild(btn);
    animationElements.set(clip.name, btn);
  }
  section.appendChild(row);
  return section;
}

function renderScaleSection(
  onChange: (scale01: number) => void,
  labels: SwatchOverlayLabels,
): HTMLDivElement {
  const section = document.createElement('div');
  section.className = 'nova-ar-section nova-ar-section--scale';
  section.style.cssText = 'display: flex; align-items: center; gap: 12px; pointer-events: auto;';
  const label = document.createElement('span');
  label.textContent = labels.scaleLabel;
  label.style.cssText = 'font: 600 13px/1 system-ui, sans-serif; color: #f8fafc;';
  const slider = document.createElement('input');
  slider.type = 'range';
  slider.min = '0';
  slider.max = '100';
  slider.value = '50';
  slider.setAttribute('aria-label', labels.scaleLabel);
  slider.style.cssText = 'flex: 1; accent-color: #0284c7;';
  slider.addEventListener('input', () => {
    const v = Number.parseInt(slider.value, 10) / 100;
    onChange(v);
  });
  section.appendChild(label);
  section.appendChild(slider);
  return section;
}

function normaliseHex(input: string): string {
  let s = input.toLowerCase();
  if (!s.startsWith('#')) s = `#${s}`;
  if (/^#[0-9a-f]{3}$/.test(s)) {
    const r = s[1];
    const g = s[2];
    const b = s[3];
    s = `#${r}${r}${g}${g}${b}${b}`;
  }
  return s;
}
