/** Build a wall/ceiling lamp `Item` from a `LampSpec`. Assets are served
 *  locally from `apps/viewer/public/models/<id>.glb`. USDZ for iOS Quick
 *  Look + rendered thumbnails are produced by the catalog pipeline's
 *  `usdz` + `thumbnail` stages (not yet generated locally — see
 *  docs/SESSION_LOG.md), so `usdz` points at its eventual path and
 *  `thumbnails` is empty until then. */
function makeLamp(spec: LampSpec, mount: 'wall' | 'ceiling'): Item {
  const materialName = mount === 'wall' ? 'Wall_Lamps' : 'Ceiling_Lamps';
  return {
    id: spec.id,
    tenantId: 'demo',
    name: spec.name,
    description: spec.description,
    placement: 'wall-ceiling',
    mountType: mount,
    category: 'lighting',
    bbox: spec.bbox,
    price: { amount: spec.price, currency: 'USD' },
    sku: spec.sku,
    assets: {
      glb: `models/${spec.id}.glb`,
      usdz: `models/${spec.id}.usdz`,
      thumbnails: [],
    },
    pbrValid: true,
    schemaVersion: 1,
    swappableMaterials: [{ label: 'Lamp finish', materialName, palette: [...LAMP_FINISH_PALETTE] }],
  };
}

