/**
 * Theme management.
 *
 * Three themes: light / dark / auto.
 *  - 'auto' = honour `prefers-color-scheme` via CSS media queries
 *    declared in index.html (no JS needed)
 *  - 'light' / 'dark' = explicit override
 */

import type { EmbedTheme } from './shared-types';

export function applyTheme(theme: EmbedTheme, root: HTMLElement = document.documentElement): void {
  root.setAttribute('data-theme', theme);
}
