/**
 * Concrete adapters for the `<model-viewer>` web component runtime.
 *
 * Three small classes each implementing one of the adapter contracts
 * from `apps/viewer/src/ui/*`:
 *
 *   - `ModelViewerMaterialAdapter` — implements `MaterialAdapter` (color
 *     swap + KHR_materials_variants). model-viewer 4.x exposes a
 *     `model.materials` collection per material slot and a top-level
 *     `variantName` setter for KHR_materials_variants.
 *   - `ModelViewerAnimationAdapter` — implements `AnimationAdapter`.
 *     model-viewer maps a single declarative `animation-name` attribute
 *     onto the embedded `AnimationMixer`; multi-clip orchestration is
 *     done by setting `animation-name` + calling `play()` / `pause()`.
 *   - `ModelViewerArScaleAdapter` — flips the `ar-scale` attribute
 *     between `fixed` and `auto` per the `ArScalePolicy`.
 *
 * Each adapter is constructed with a reference to the live
 * `<model-viewer>` DOM element. They are *defensive*: if the element
 * isn't ready (no `model` yet) the call no-ops gracefully and reports
 * a soft failure to the controller, which propagates `adapter-failed`
 * up to the embed host.
 */

import type { AnimationAdapter } from '../ui/animation-controller';
import type { MaterialAdapter } from '../ui/material-swap';
import { arScaleAttribute, type ArScalePolicy } from '../ui/ar-scale-policy';

/** Subset of the model-viewer DOM element we use — keeps the adapters
 *  testable with a tiny stub without pulling the full @google/model-viewer
 *  typings into the test harness. */
export interface ModelViewerLike extends Pick<HTMLElement, 'setAttribute' | 'getAttribute'> {
  readonly model?: ModelViewerModelLike | null;
  variantName?: string | null;
  availableAnimations?: readonly string[];
  // Three.js-style API for triggering play / pause exposed on the element.
  play?(opts?: { repetitions?: number }): void;
  pause?(): void;
  timeScale?: number;
  currentTime?: number;
  paused?: boolean;
  addEventListener(type: string, listener: (e: Event) => void): void;
  removeEventListener(type: string, listener: (e: Event) => void): void;
}

export interface ModelViewerModelLike {
  readonly materials: readonly ModelViewerMaterialLike[];
}

export interface ModelViewerMaterialLike {
  readonly name: string;
  readonly pbrMetallicRoughness?: {
    /** Linear-RGBA in [0..1]. */
    setBaseColorFactor(rgba: readonly [number, number, number, number]): void;
    readonly baseColorFactor: readonly [number, number, number, number];
  };
}

export class ModelViewerMaterialAdapter implements MaterialAdapter {
  private readonly originalColors = new Map<string, readonly [number, number, number, number]>();

  constructor(private readonly el: ModelViewerLike) {}

  applyVariant(variantName: string): boolean {
    // model-viewer exposes a `variantName` setter for KHR_materials_variants.
    // Setting an unknown variant is a no-op in model-viewer 4.x; we can't
    // introspect availability from the DOM type, so we set + verify.
    try {
      this.el.variantName = variantName;
      return this.el.variantName === variantName;
    } catch {
      return false;
    }
  }

  overrideColor(materialName: string, hex: string): boolean {
    const material = this.findMaterial(materialName);
    if (!material?.pbrMetallicRoughness) return false;
    const rgba = hexToLinearRgba(hex);
    if (!this.originalColors.has(materialName)) {
      const cur = material.pbrMetallicRoughness.baseColorFactor;
      this.originalColors.set(materialName, [cur[0], cur[1], cur[2], cur[3]]);
    }
    material.pbrMetallicRoughness.setBaseColorFactor(rgba);
    return true;
  }

  resetAll(): void {
    // Restore each remembered base-color override, even if the model is
    // currently unloaded (no-op when findMaterial returns undefined).
    if (this.el.model) {
      for (const [name, rgba] of this.originalColors) {
        const material = this.findMaterial(name);
        material?.pbrMetallicRoughness?.setBaseColorFactor(rgba);
      }
    }
    this.originalColors.clear();
    // Clear any active variant (back to glTF default). This runs even
    // when `el.model` isn't ready — the setter is a no-op queue then.
    try {
      this.el.variantName = null;
    } catch {
      // Some model-viewer builds reject `null` — empty string also works.
      try {
        this.el.variantName = '';
      } catch {
        // ignore
      }
    }
  }

  private findMaterial(name: string): ModelViewerMaterialLike | undefined {
    const materials = this.el.model?.materials;
    if (!materials) return undefined;
    return materials.find((m) => m.name === name);
  }
}

export class ModelViewerAnimationAdapter implements AnimationAdapter {
  constructor(
    private readonly el: ModelViewerLike,
    private readonly onFinished?: (name: string) => void,
  ) {
    el.addEventListener('finished', this.handleFinished);
  }

  private readonly handleFinished = (): void => {
    const current = this.el.getAttribute('animation-name');
    if (current) this.onFinished?.(current);
  };

  play(name: string, loop: boolean): boolean {
    const available = this.el.availableAnimations;
    if (Array.isArray(available) && !available.includes(name)) return false;
    this.el.setAttribute('animation-name', name);
    // model-viewer's play() takes an options object — repetitions Infinity
    // means loop, repetitions 1 means play once.
    this.el.play?.({ repetitions: loop ? Number.POSITIVE_INFINITY : 1 });
    return true;
  }

  stop(name?: string): void {
    if (name !== undefined) {
      const current = this.el.getAttribute('animation-name');
      if (current !== name) return; // only stop the named one
    }
    this.el.pause?.();
    if (this.el.currentTime !== undefined) {
      this.el.currentTime = 0;
    }
  }

  dispose(): void {
    this.el.removeEventListener('finished', this.handleFinished);
  }
}

export class ModelViewerArScaleAdapter {
  constructor(private readonly el: ModelViewerLike) {}

  apply(policy: ArScalePolicy): void {
    this.el.setAttribute('ar-scale', arScaleAttribute(policy));
  }
}

// ── pure helpers ─────────────────────────────────────────────────────

/** `#rrggbb` / `#rrggbbaa` → linear-space RGBA in [0..1].
 *
 * glTF baseColorFactor is in LINEAR RGB. The shopper picks sRGB
 * (web standard); we gamma-correct each channel via the standard
 * 2.4 power curve approximation. */
export function hexToLinearRgba(hex: string): readonly [number, number, number, number] {
  let s = hex.replace(/^#/, '').toLowerCase();
  if (s.length === 3) {
    s = s
      .split('')
      .map((c) => c + c)
      .join('');
  }
  let alpha = 1;
  if (s.length === 8) {
    alpha = parseInt(s.slice(6, 8), 16) / 255;
    s = s.slice(0, 6);
  }
  if (s.length !== 6 || !/^[0-9a-f]{6}$/.test(s)) return [1, 1, 1, 1];
  const r = parseInt(s.slice(0, 2), 16) / 255;
  const g = parseInt(s.slice(2, 4), 16) / 255;
  const b = parseInt(s.slice(4, 6), 16) / 255;
  return [srgbToLinear(r), srgbToLinear(g), srgbToLinear(b), alpha];
}

function srgbToLinear(c: number): number {
  if (c <= 0.04045) return c / 12.92;
  return Math.pow((c + 0.055) / 1.055, 2.4);
}
