/**
 * Pure-function DOM renderer for the viewer UI.
 *
 * No framework. The viewer is intentionally framework-free so the
 * bundle is tiny and there's no React-init delay between iframe load
 * and visible UI. Each render() returns a fresh DOM tree the caller
 * mounts into the host element.
 */

import type { Item } from '@nova-ar/types';
import type { EmbedLanguage } from '../shared-types';
import { pickStrings } from '../i18n/strings';

export interface RenderState {
  readonly language: EmbedLanguage;
  readonly currency: string | null;
  readonly items: readonly Item[];
  readonly selectedItemId: string | null;
  readonly placementHint: 'floor' | 'surface' | 'wall-ceiling' | null;
  readonly arRuntimeAvailable: boolean;
  readonly errorMessage: string | null;
}

export interface RenderCallbacks {
  onSelectItem(itemId: string): void;
  onLaunchAr(itemId: string): void;
  onRetry(): void;
}

/**
 * Render the full viewer UI into `host`. Idempotent — call it again
 * with new state and the host's children are replaced.
 */
export function render(host: HTMLElement, state: RenderState, cbs: RenderCallbacks): void {
  const strings = pickStrings(state.language);
  host.replaceChildren(
    div('viewer-root', { style: rootStyle() }, [
      header(strings['app.title'], strings['app.subtitle']),
      state.errorMessage
        ? errorBanner(state.errorMessage, strings['control.retry'], cbs.onRetry)
        : null,
      div('viewer-body', { style: bodyStyle() }, [
        catalogDrawer(state, strings, cbs),
        itemDetail(state, strings, cbs),
      ]),
    ]),
  );
}

function header(title: string, subtitle: string): HTMLElement {
  return div('viewer-header', { style: headerStyle() }, [
    el('h1', '', { style: 'margin:0;font-size:14px;font-weight:600;', text: title }),
    el('p', '', { style: 'margin:2px 0 0 0;font-size:12px;color:var(--ink-dim);', text: subtitle }),
  ]);
}

function errorBanner(message: string, retryLabel: string, onRetry: () => void): HTMLElement {
  const btn = el('button', '', {
    text: retryLabel,
    style:
      'margin-left:auto;padding:4px 10px;border:0;border-radius:6px;background:var(--bg);color:var(--ink);cursor:pointer;',
  });
  btn.addEventListener('click', onRetry);
  return div('viewer-error', { style: errorBannerStyle() }, [
    el('span', '', { text: message, style: 'flex:1;' }),
    btn,
  ]);
}

function catalogDrawer(
  state: RenderState,
  strings: ReturnType<typeof pickStrings>,
  cbs: RenderCallbacks,
): HTMLElement {
  if (state.items.length === 0) {
    return div('viewer-catalog viewer-catalog-empty', { style: drawerStyle() }, [
      el('p', '', {
        text: strings['catalog.empty'],
        style: 'color:var(--ink-dim);font-size:13px;',
      }),
    ]);
  }
  return div('viewer-catalog', { style: drawerStyle() }, [
    el('h2', '', {
      text: strings['catalog.heading'],
      style:
        'margin:0 0 10px 0;font-size:12px;font-weight:600;text-transform:uppercase;letter-spacing:0.06em;color:var(--ink-dim);',
    }),
    div(
      'viewer-catalog-list',
      { style: 'display:grid;gap:8px;' },
      state.items.map((item) => itemRow(item, item.id === state.selectedItemId, cbs.onSelectItem)),
    ),
  ]);
}

function itemRow(item: Item, selected: boolean, onSelect: (id: string) => void): HTMLElement {
  const row = div(
    'viewer-item-row',
    {
      style: itemRowStyle(selected),
      role: 'button',
      tabindex: '0',
      'aria-pressed': String(selected),
      'data-item-id': item.id,
    },
    [
      el('div', '', {
        text: item.name,
        style: 'font-size:13px;font-weight:500;color:var(--ink);',
      }),
      el('div', '', {
        text: `${item.bbox.length}×${item.bbox.width}×${item.bbox.height} cm`,
        style: 'font-size:11px;color:var(--ink-dim);margin-top:2px;',
      }),
    ],
  );
  row.addEventListener('click', () => onSelect(item.id));
  row.addEventListener('keydown', (e) => {
    if ((e as KeyboardEvent).key === 'Enter' || (e as KeyboardEvent).key === ' ') {
      e.preventDefault();
      onSelect(item.id);
    }
  });
  return row;
}

function itemDetail(
  state: RenderState,
  strings: ReturnType<typeof pickStrings>,
  cbs: RenderCallbacks,
): HTMLElement {
  const selected = state.selectedItemId
    ? state.items.find((i) => i.id === state.selectedItemId)
    : null;
  if (!selected) {
    return div('viewer-detail viewer-detail-empty', { style: detailStyle() }, [
      el('p', '', {
        text: strings['app.subtitle'],
        style: 'color:var(--ink-dim);font-size:14px;text-align:center;padding:32px 16px;',
      }),
    ]);
  }
  const placementLabel = strings[`placement.${selected.placement}`] ?? '';
  const priceLine = selected.price
    ? `${state.currency ?? selected.price.currency} ${selected.price.amount}`
    : '';
  const launch = el('button', '', {
    text: strings['item.placeInRoom'],
    style: launchButtonStyle(state.arRuntimeAvailable),
    disabled: state.arRuntimeAvailable ? null : 'true',
  });
  launch.addEventListener('click', () => cbs.onLaunchAr(selected.id));
  return div('viewer-detail', { style: detailStyle() }, [
    el('div', '', {
      text: selected.name,
      style: 'font-size:18px;font-weight:600;color:var(--ink);',
    }),
    el('div', '', {
      text: selected.description,
      style: 'color:var(--ink-dim);font-size:13px;margin-top:6px;',
    }),
    el('div', '', {
      text: placementLabel,
      style:
        'font-size:12px;color:var(--accent);margin-top:14px;text-transform:uppercase;letter-spacing:0.06em;',
    }),
    el('div', '', {
      text: priceLine,
      style: 'font-size:16px;color:var(--ink);margin-top:8px;font-weight:600;',
    }),
    launch,
  ]);
}

// ---------- DOM helpers ----------

function el(
  tag: string,
  className: string,
  opts: {
    text?: string;
    style?: string;
    [attr: string]: string | null | undefined;
  },
): HTMLElement {
  const node = document.createElement(tag);
  if (className) node.className = className;
  if (opts.text !== undefined) node.textContent = opts.text;
  if (opts.style) node.setAttribute('style', opts.style);
  for (const [k, v] of Object.entries(opts)) {
    if (k === 'text' || k === 'style' || v === null || v === undefined) continue;
    node.setAttribute(k, v);
  }
  return node;
}

function div(
  className: string,
  attrs: Record<string, string>,
  children: (HTMLElement | null)[] = [],
): HTMLElement {
  const node = document.createElement('div');
  if (className) node.className = className;
  for (const [k, v] of Object.entries(attrs)) {
    if (v != null) node.setAttribute(k, v);
  }
  for (const child of children) {
    if (child) node.append(child);
  }
  return node;
}

// ---------- Inline styles (kept here to avoid a CSS build step) ----------

const rootStyle = () => 'display:flex;flex-direction:column;height:100%;background:var(--bg);';

const headerStyle = () =>
  'padding:14px 20px;border-bottom:1px solid var(--border);background:var(--panel);';

const bodyStyle = () => 'flex:1;display:grid;grid-template-columns:240px 1fr;min-height:0;';

const drawerStyle = () =>
  'background:var(--panel);border-inline-end:1px solid var(--border);padding:16px 14px;overflow:auto;';

const detailStyle = () => 'padding:20px;overflow:auto;background:var(--bg);';

const errorBannerStyle = () =>
  'display:flex;align-items:center;gap:10px;padding:10px 16px;background:var(--error);color:#fff;font-size:13px;';

const itemRowStyle = (selected: boolean) =>
  `padding:10px 12px;border-radius:8px;cursor:pointer;background:${selected ? 'var(--accent)' : 'transparent'};color:${selected ? 'var(--accent-ink)' : 'var(--ink)'};border:1px solid ${selected ? 'transparent' : 'var(--border)'};`;

const launchButtonStyle = (enabled: boolean) =>
  `display:block;margin-top:20px;padding:12px 18px;width:100%;border:0;border-radius:10px;background:${enabled ? 'var(--accent)' : 'var(--border)'};color:${enabled ? 'var(--accent-ink)' : 'var(--ink-dim)'};font-size:14px;font-weight:600;cursor:${enabled ? 'pointer' : 'not-allowed'};min-height:44px;`;
