/**
 * Per-material colour swap controller.
 *
 * Pure-logic orchestrator over a runtime adapter — the adapter (one
 * for model-viewer, one for the WebXR Three.js path) implements the
 * concrete material override + variant switch. This file enforces:
 *
 *   1. The swap targets a material the item DECLARES swappable. A
 *      request for `materialName: 'ChairLeg'` on an item whose only
 *      declared row is `'ChairFabric'` is rejected — the legs stay
 *      fixed regardless of what the embed JS sends.
 *
 *   2. The colour is one of the declared palette entries (when
 *      `strictPalette` is true). Strict mode prevents an embed-side
 *      bug or hostile host page from feeding arbitrary colours into
 *      the renderer.
 *
 *   3. The adapter is asked to switch a `KHR_materials_variants`
 *      variant first; only if that returns `false` does the override
 *      path fire. This matches the modern glTF authoring flow.
 */

import type { Item, SwappableMaterial } from '@nova-ar/types';

export interface MaterialAdapter {
  /** Try to activate a glTF materials-variants variant by name.
   *  Returns true when the variant exists + was applied; false when
   *  the .glb has no such variant (caller falls back to overrideColor). */
  applyVariant(variantName: string): boolean;
  /** Mutate a single named material's base colour. */
  overrideColor(materialName: string, hex: string): boolean;
  /** Restore every overridden colour + reset variant selection. */
  resetAll(): void;
}

export interface MaterialSwapControllerOptions {
  readonly item: Item;
  readonly adapter: MaterialAdapter;
  /** When true (default), the runtime rejects swaps to colours
   *  outside the declared palette. Set false for the dashboard
   *  preview where designers iterate on free-form colours. */
  readonly strictPalette?: boolean;
}

export type SwapResult =
  | { ok: true; via: 'variant' | 'override'; materialName: string; hex: string }
  | { ok: false; reason: 'unknown-material' | 'palette-rejected' | 'adapter-failed' };

export class MaterialSwapController {
  private readonly item: Item;
  private readonly adapter: MaterialAdapter;
  private readonly strictPalette: boolean;
  private readonly declared = new Map<string, SwappableMaterial>();

  constructor(opts: MaterialSwapControllerOptions) {
    this.item = opts.item;
    this.adapter = opts.adapter;
    this.strictPalette = opts.strictPalette ?? true;
    for (const row of opts.item.swappableMaterials ?? []) {
      this.declared.set(row.materialName, row);
    }
  }

  /** Item id this controller is bound to — set by the viewer when the
   *  active item changes so callers can confirm the swap is for the
   *  right item. */
  itemId(): string {
    return this.item.id;
  }

  /** Rows the embed-side swatch UI should render. */
  swatchRows(): readonly SwappableMaterial[] {
    return this.item.swappableMaterials ?? [];
  }

  swap(materialName: string, hex: string): SwapResult {
    const row = this.declared.get(materialName);
    if (!row) return { ok: false, reason: 'unknown-material' };

    const normalisedHex = normaliseHex(hex);
    if (this.strictPalette) {
      const palette = row.palette.map(normaliseHex);
      if (!palette.includes(normalisedHex)) {
        return { ok: false, reason: 'palette-rejected' };
      }
    }

    // Prefer the KHR_materials_variants path when the author declared
    // variant names. Each palette index maps to one variant name.
    if (row.variantNames && row.variantNames.length > 0) {
      const palette = row.palette.map(normaliseHex);
      const idx = palette.indexOf(normalisedHex);
      const variantName = idx >= 0 ? row.variantNames[idx] : undefined;
      if (variantName !== undefined) {
        if (this.adapter.applyVariant(variantName)) {
          return { ok: true, via: 'variant', materialName, hex: normalisedHex };
        }
      }
    }

    // Fallback: direct material.color override on the named slot.
    if (this.adapter.overrideColor(materialName, normalisedHex)) {
      return { ok: true, via: 'override', materialName, hex: normalisedHex };
    }
    return { ok: false, reason: 'adapter-failed' };
  }

  /** Restore every swap to the .glb defaults. */
  reset(): void {
    this.adapter.resetAll();
  }
}

function normaliseHex(input: string): string {
  let s = input.toLowerCase();
  if (!s.startsWith('#')) s = `#${s}`;
  // Expand #rgb → #rrggbb so palette comparisons land on a canonical form.
  if (/^#[0-9a-f]{3}$/.test(s)) {
    const r = s[1];
    const g = s[2];
    const b = s[3];
    s = `#${r}${r}${g}${g}${b}${b}`;
  }
  return s;
}
