/**
 * GLB animation playback controller.
 *
 * Same pattern as `material-swap.ts`: pure-logic orchestrator over a
 * runtime adapter the viewer wires (`THREE.AnimationMixer` for WebXR,
 * `<model-viewer>` `animation-name` attribute for the fallback path).
 *
 * Gates:
 *   1. The animation must be DECLARED — request for an undeclared
 *      `playableAnimations[].name` is rejected with `unknown-animation`.
 *      Prevents a shopper / hostile host page from triggering arbitrary
 *      glTF clips (some authors leave debug clips named "T-pose" in
 *      the .glb; we never want those to play).
 *   2. Loop respects the per-clip `loop` flag.
 *
 * The controller does NOT own playback timing — the adapter does
 * (because `AnimationMixer.update(dt)` lives on the render loop, and
 * `<model-viewer>` runs its own). The controller only orchestrates
 * play / stop / restart.
 */

import type { Item, PlayableAnimation } from '@nova-ar/types';

export interface AnimationAdapter {
  /** Play the named clip. Returns true if the clip exists, false otherwise. */
  play(name: string, loop: boolean): boolean;
  /** Stop a single clip (or all clips if name is undefined). */
  stop(name?: string): void;
}

export interface AnimationControllerOptions {
  readonly item: Item;
  readonly adapter: AnimationAdapter;
}

export type PlayResult =
  | { ok: true; name: string; loop: boolean }
  | { ok: false; reason: 'unknown-animation' | 'adapter-missing' };

export class AnimationController {
  private readonly item: Item;
  private readonly adapter: AnimationAdapter;
  private readonly declared = new Map<string, PlayableAnimation>();
  private readonly activeClips = new Set<string>();

  constructor(opts: AnimationControllerOptions) {
    this.item = opts.item;
    this.adapter = opts.adapter;
    for (const clip of opts.item.playableAnimations ?? []) {
      this.declared.set(clip.name, clip);
    }
  }

  /** Item id this controller is bound to. */
  itemId(): string {
    return this.item.id;
  }

  /** Animations the chip row should render. */
  chips(): readonly PlayableAnimation[] {
    return this.item.playableAnimations ?? [];
  }

  /** Currently-playing animation names (drives chip selected-state). */
  activeNames(): readonly string[] {
    return [...this.activeClips];
  }

  play(name: string): PlayResult {
    const clip = this.declared.get(name);
    if (!clip) return { ok: false, reason: 'unknown-animation' };
    const loop = clip.loop ?? false;
    if (!this.adapter.play(name, loop)) {
      return { ok: false, reason: 'adapter-missing' };
    }
    this.activeClips.add(name);
    return { ok: true, name, loop };
  }

  stop(name?: string): void {
    this.adapter.stop(name);
    if (name === undefined) {
      this.activeClips.clear();
    } else {
      this.activeClips.delete(name);
    }
  }

  /** Called by the adapter when a non-looping clip finishes naturally. */
  onClipFinished(name: string): void {
    this.activeClips.delete(name);
  }
}
