/**
 * Local copies of the embed's public types — viewer + embed agree on
 * the wire shape.
 *
 * The viewer can't depend on `@novagates/ar-embed` directly because
 * embed depends on the viewer's URL (circular concerns), so we mirror
 * the relevant types here and rely on a cross-package test to
 * detect drift.
 */

import type { PlacementClass, Pose } from '@nova-ar/types';

export type EmbedTheme = 'light' | 'dark' | 'auto';
export type EmbedLanguage = 'en' | 'ar' | 'fr' | 'ar-KW';

export type NovaArEventKind =
  | 'session.start'
  | 'session.end'
  | 'item.viewed'
  | 'item.placed'
  | 'item.removed'
  | 'item.manipulated'
  | 'anchor.lost'
  | 'anchor.regained'
  | 'arrangement.saved'
  | 'arrangement.shared'
  | 'error';

export type NovaArEvent =
  | { readonly kind: 'session.start'; readonly runtimePath: string }
  | { readonly kind: 'session.end' }
  | { readonly kind: 'item.viewed'; readonly itemId: string }
  | {
      readonly kind: 'item.placed';
      readonly placementId: string;
      readonly itemId: string;
      readonly placement: PlacementClass;
      readonly pose: Pose;
    }
  | { readonly kind: 'item.removed'; readonly placementId: string }
  | {
      readonly kind: 'item.manipulated';
      readonly placementId: string;
      readonly pose: Pose;
    }
  | { readonly kind: 'anchor.lost'; readonly placementId: string }
  | { readonly kind: 'anchor.regained'; readonly placementId: string }
  | { readonly kind: 'arrangement.saved'; readonly arrangementId: string }
  | {
      readonly kind: 'arrangement.shared';
      readonly format: 'link' | 'video' | 'card';
      readonly url?: string;
    }
  | { readonly kind: 'error'; readonly code: string; readonly message: string };

/** Commands the host sends down to us. */
export interface CommandEnvelope {
  readonly kind:
    | 'selectItem'
    | 'updateProduct'
    | 'setSkin'
    | 'setMaterialColor'
    | 'playAnimation'
    | 'stopAnimation'
    | 'setLanguage'
    | 'setTheme';
  readonly payload: unknown;
}

/** Bridge envelope shared with the embed JS. */
export interface BridgeMessage {
  readonly _nova: true;
  readonly v: 1;
  readonly id: string;
  readonly replyTo?: string;
  readonly type: 'event' | 'command' | 'ack';
  readonly payload: unknown;
}

/** Guards. */
export function isTheme(value: string): value is EmbedTheme {
  return value === 'light' || value === 'dark' || value === 'auto';
}

export function isLanguage(value: string): value is EmbedLanguage {
  return value === 'en' || value === 'ar' || value === 'fr' || value === 'ar-KW';
}

const KNOWN_COMMANDS = new Set<CommandEnvelope['kind']>([
  'selectItem',
  'updateProduct',
  'setSkin',
  'setMaterialColor',
  'playAnimation',
  'stopAnimation',
  'setLanguage',
  'setTheme',
]);

export function isCommandKind(value: unknown): value is CommandEnvelope['kind'] {
  return typeof value === 'string' && KNOWN_COMMANDS.has(value as CommandEnvelope['kind']);
}
